
'use client';

import React, { useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { eventService } from '@/services/event-service';
import toast from 'react-hot-toast';
import Swal from 'sweetalert2';
import imageCompression from 'browser-image-compression';
import palette from '@/config/palette';
import PaymentInstructionBox from '@/components/user/payment/PaymentInstructionBox';

export default function EventRegisterPage() {
  const params = useParams();
  const router = useRouter();
  const queryClient = useQueryClient();
  
  const key = params?.key as string;

  const { data: event, isLoading } = useQuery({
    queryKey: ['event', key],
    queryFn: () => eventService.getEvent(key),
    enabled: !!key, 
  });

  const [paymentFile, setPaymentFile] = useState<File | null>(null);
  const [paymentPreview, setPaymentPreview] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCompressing, setIsCompressing] = useState(false);
  const [formErrors, setFormErrors] = useState<any>(null);
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
  const file = e.target.files?.[0];
  if (!file) {
    setPaymentFile(null);
    setPaymentPreview(null);
    return;
  }

  if (file.type === 'application/pdf') {
    setPaymentFile(file);
    setPaymentPreview(null);
    return;
  }

  setIsCompressing(true);
  try {
    const options = { maxSizeMB: 0.5, maxWidthOrHeight: 1280, useWebWorker: true };
    const compressedFile = await imageCompression(file, options);
    setPaymentFile(compressedFile);
    
    // Create preview
    const reader = new FileReader();
    reader.onloadend = () => {
      setPaymentPreview(reader.result as string);
    };
    reader.readAsDataURL(compressedFile);
  } catch (error) {
    setPaymentFile(file);
    
    // Create preview for original file
    const reader = new FileReader();
    reader.onloadend = () => {
      setPaymentPreview(reader.result as string);
    };
    reader.readAsDataURL(file);
  } finally {
    setIsCompressing(false);
  }
};

  const isPaid = event ? Number(event.price) > 0 : false;

  // 🔥 1. FETCH STATUS REGISTRASI UNTUK CEK DOBEL DAFTAR / REJECT 🔥
const { data: regStatus, isLoading: isStatusLoading } = useQuery({
    queryKey: ['event-status', key], // (Pastikan ini 'competition-status' kalau di file lomba)
    queryFn: async () => {
      try {
        return await eventService.checkStatusRegistrations(key);
      } catch (error: any) {
        return null;
      }
    },
    enabled: !!key,
    retry: false,
    
    // 🔥 TAMBAHIN DUA BARIS SAKTI INI BRO! 🔥
    staleTime: 0, 
    gcTime: 0     
  });

// Logika Penjaga Gawang
  const statusStr = regStatus?.status?.toUpperCase() || '';
  const isRejected = statusStr.includes('REJECT') || statusStr.includes('TOLAK');

  // 🔥 TAMBAHIN BARIS INI YANG KELUPAAN DI EVENT 🔥
  const isUnregistered = statusStr === 'UNREGISTERED'; 

  // 🔥 TAMBAHIN INI BIAR DRAFT BISA LEWAT 🔥
  const isDraft = statusStr === 'DRAFT';
  
  // Berarti dia "Sudah Daftar" HANYA JIKA statusnya bukan REJECT, bukan UNREGISTERED, dan bukan DRAFT
  const isAlreadyRegistered = regStatus && regStatus.status && !isRejected && !isUnregistered && !isDraft;

  // 🔥 2. EFEK USIR USER KALAU UDAH DAFTAR 🔥
  React.useEffect(() => {
    if (isAlreadyRegistered) {
      Swal.fire({
        icon: 'info',
        title: 'ALREADY REGISTERED',
        text: 'You have already submitted a registration protocol for this event. Check your dashboard for updates.',
        background: palette.onyx,
        color: palette.stucco,
        confirmButtonColor: palette.walnut,
        allowOutsideClick: false,
        customClass: {
          popup: 'border border-[#7b787a] rounded-none',
          title: 'font-black tracking-[0.2em] uppercase text-xl',
          confirmButton: 'font-bold tracking-widest uppercase rounded-none px-8 py-3'
        }
      }).then(() => {
        router.push('/dashboard');
      });
    }
  }, [isAlreadyRegistered, router]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormErrors(null);

    if (isPaid && !paymentFile) {
      return toast.error('PAYMENT PROOF IS REQUIRED.', {
        style: { background: palette.onyx, color: palette.stucco, border: `1px solid ${palette.graphite}` }
      });
    }

    // Beda message untuk event gratis vs berbayar
    const confirmationMessage = isPaid 
      ? 'Are you sure you want to submit? Please ensure your payment proof is correct. Data cannot be altered later.'
      : 'Are you sure you want to register for this free event? Once confirmed, you cannot cancel your registration.';

    const confirmation = await Swal.fire({
      icon: 'question',
      title: isPaid ? 'CONFIRM SUBMISSION?' : 'CONFIRM REGISTRATION?',
      text: confirmationMessage,
      background: palette.onyx,
      color: palette.stucco,
      showCancelButton: true,
      confirmButtonColor: palette.walnut,
      cancelButtonColor: palette.graphite,
      confirmButtonText: isPaid ? 'SUBMIT NOW' : 'YES, REGISTER',
      cancelButtonText: 'CANCEL',
      customClass: {
        popup: 'border border-[#7b787a] rounded-none',
        title: 'font-black tracking-[0.2em] uppercase text-xl',
        confirmButton: 'font-bold tracking-widest uppercase rounded-none px-6 py-2',
        cancelButton: 'font-bold tracking-widest uppercase rounded-none px-6 py-2'
      }
    });

    if (!confirmation.isConfirmed) return;

    setIsSubmitting(true);
    try {
      await eventService.submitFinal(key, paymentFile as File);
      toast.success('Registration protocol submitted successfully!', {
        style: { background: palette.onyx, color: palette.stucco, border: `1px solid ${palette.graphite}` }
      });
      
      queryClient.invalidateQueries({ queryKey: ['event', key] });
      router.push('/dashboard/event'); 
    } catch (error: any) {
      if (error.isValidationError) {
        const validationErrors = error.errors;

        if (validationErrors.status) {
          Swal.fire({
            title: 'ACCESS RESTRICTED',
            text: validationErrors.status[0],
            icon: 'warning',
            background: palette.onyx,
            color: palette.stucco,
            confirmButtonColor: palette.walnut,
            confirmButtonText: 'BACK TO DASHBOARD',
            customClass: {
              popup: 'border-2 border-[#494947] rounded-none shadow-[8px_8px_0px_#1a1a1a]', 
              title: 'font-black tracking-[0.2em]',
            }
          }).then(() => {
            router.push('/dashboard');
          });
        } 
        else {
          setFormErrors(validationErrors);
          
          Swal.fire({
            title: 'DATA REJECTED',
            text: isPaid 
              ? 'Data entry protocol rejected. Please verify your clearance fee proof.'
              : 'Registration failed. Please try again.',
            icon: 'error',
            background: palette.onyx,
            color: palette.stucco,
            confirmButtonColor: '#ef4444',
            confirmButtonText: 'REVIEW INPUTS',
            customClass: {
              popup: 'border-2 border-[#494947] rounded-none shadow-[8px_8px_0px_#1a1a1a]', 
              title: 'font-black tracking-[0.2em]',
            }
          });
        }

      } else {
        Swal.fire({
          title: 'SUBMISSION FAILED',
          text: error.message || 'Registration protocol failed to execute.',
          icon: 'error',
          background: palette.onyx,
          color: palette.stucco,
          confirmButtonColor: '#ef4444',
          confirmButtonText: 'CLOSE',
          customClass: {
            popup: 'border-2 border-[#494947] rounded-none shadow-[8px_8px_0px_#1a1a1a]', 
            title: 'font-black tracking-[0.2em]',
          }
        });
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  // Layar Loading ditahan sampai API checkStatus selesai!
  if (isLoading || isStatusLoading) return <div className="min-h-screen flex items-center justify-center font-bold tracking-[0.3em] uppercase animate-pulse bg-[#0a0a0a]" style={{ color: palette.ash }}>LOADING EVENT...</div>;
  if (isAlreadyRegistered) return <div className="min-h-screen flex items-center justify-center font-bold tracking-[0.3em] uppercase bg-[#0a0a0a]" style={{ color: palette.ash }}>CHECKING REGISTRATION...</div>;
  if (!event) return <div className="min-h-screen flex items-center justify-center font-bold tracking-[0.3em] uppercase bg-[#0a0a0a]" style={{ color: palette.ash }}>EVENT NOT FOUND.</div>;

  return (
    <div className="relative py-12 min-h-screen">
      {/* <div className="fixed inset-0 z-0 pointer-events-none w-full h-full">
        <Beams beamWidth={3} beamHeight={30} beamNumber={20} lightColor={palette.greige} speed={2} noiseIntensity={1.75} scale={0.2} rotation={30} />
      </div> */}

      <div className="relative z-10 max-w-3xl mx-auto px-4">
        <button onClick={() => router.back()} className="mb-12 font-bold text-xs tracking-[0.3em] uppercase cursor-pointer transition-colors flex items-center gap-3 hover:text-white" style={{ color: palette.ash }}>
          <span className="w-8 h-[1px] block transition-all" style={{ backgroundColor: palette.ash }}></span> BACK
        </button>

        <div className="p-10 md:p-14 border backdrop-blur-md relative overflow-hidden transition-all duration-700 ease-[cubic-bezier(0.25,1,0.5,1)]" style={{ backgroundColor: palette.onyx, borderColor: palette.graphite, boxShadow: '0 10px 30px -10px rgba(0,0,0,0.5)' }}>
          <div className="absolute top-0 right-0 p-8 opacity-[0.03] pointer-events-none">
            <span className="text-9xl font-black italic" style={{ color: palette.stucco }}>E</span>
          </div>
          
          <div className="flex items-center gap-3 mb-6 relative z-10">
              <span className="w-2 h-2 rounded-full animate-pulse" style={{ backgroundColor: palette.stucco, boxShadow: `0 0 10px ${palette.stucco}` }}></span>
              <p className="text-[10px] font-bold tracking-[0.4em] uppercase" style={{ color: palette.ash }}>EVENT REGISTRATION</p>
          </div>

          <h1 className="text-4xl md:text-6xl font-black mb-6 uppercase tracking-widest relative z-10" style={{ color: palette.stucco }}>
            {event.title || 'UNKNOWN EVENT'}
          </h1>
          <p className="mb-10 text-sm font-medium tracking-wide leading-relaxed relative z-10" style={{ color: palette.ash }}>
            {event.description || 'Secure your pass for this exclusive gathering.'}
          </p>

          <div className="border p-8 mb-10 flex flex-col md:flex-row justify-between items-start md:items-end gap-4 relative z-10" style={{ backgroundColor: palette.obsidian, borderColor: palette.graphite }}>
            <div>
              <p className="text-[10px] tracking-[0.2em] mb-2 uppercase" style={{ color: palette.ash }}>CLEARANCE FEE</p>
              <span className="text-3xl font-black tracking-widest" style={{ color: isPaid ? palette.stucco : palette.greige }}>
                {isPaid ? `Rp ${Number(event.price).toLocaleString('id-ID')}` : 'NO CHARGE'}
              </span>
            </div>
            <div className="text-right hidden md:block">
                <p className="text-[10px] tracking-[0.2em] mb-2 uppercase" style={{ color: palette.ash }}>STATUS</p>
                <div className="text-xs font-bold uppercase tracking-widest" style={{ color: isRejected ? '#ef4444' : palette.greige }}>
                    {isRejected ? 'REJECTED - AWAITING RESUBMISSION' : isPaid ? 'AWAITING PAYMENT' : 'READY TO SECURE'}
                </div>
            </div>
          </div>

          {/* 🔥 PAYMENT INSTRUCTION BOX — only for paid events with payment details 🔥 */}
          {isPaid && event.payment_details && (
            <div className="mb-10 relative z-10">
              <PaymentInstructionBox
                paymentDetails={event.payment_details}
                price={Number(event.price)}
              />
            </div>
          )}

          {/* 🔥 3. KASIH WARNING KALAU DIA MAU RE-SUBMIT KARENA REJECT 🔥 */}
          {isRejected && (
            <div className="border p-6 mb-8 relative z-10" style={{ borderColor: '#ef4444', backgroundColor: 'rgba(239, 68, 68, 0.1)' }}>
              <h3 className="text-red-500 font-bold tracking-[0.2em] uppercase mb-2 text-sm">⚠️ PREVIOUS SUBMISSION REJECTED</h3>
              <p className="text-red-200 text-sm mb-1">Your previous registration was rejected by the Administrator.</p>
              {regStatus?.rejection_reason && (
                <p className="text-red-200 text-sm font-bold mb-3">Reason: {regStatus.rejection_reason}</p>
              )}
              <p className="text-white text-[10px] tracking-[0.2em] uppercase font-bold">
                {isPaid ? 'Please upload a valid payment proof and resubmit below.' : 'Please resubmit your registration below.'}
              </p>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-10 relative z-10">
            {isPaid && (
              <div>
                <label className="block text-[10px] font-bold mb-4 uppercase tracking-[0.2em]" style={{ color: palette.greige }}>
                  PAYMENT PROOF (JPG/PNG/PDF) *
                </label>
                <input 
                  type="file" accept=".jpg,.jpeg,.png,.pdf"
                  onChange={handleFileUpload}
                  className="w-full text-sm border p-4 cursor-pointer file:mr-6 file:py-3 file:px-6 file:border-0 file:font-bold file:uppercase file:tracking-widest transition-all focus:outline-none focus:border-white/50"
                  style={{ backgroundColor: palette.obsidian, borderColor: formErrors?.payment_proof ? '#ef4444' : palette.graphite, color: palette.ash }}
                />
                {formErrors?.payment_proof && <p className="text-red-500 text-[10px] mt-3 font-bold uppercase tracking-[0.2em]">⚠️ {formErrors.payment_proof[0]}</p>}
                
                {paymentPreview && (
                  <div className="mt-4 border p-4" style={{ borderColor: palette.graphite, backgroundColor: palette.obsidian }}>
                    <p className="text-[10px] font-bold mb-3 uppercase tracking-[0.2em]" style={{ color: palette.greige }}>PREVIEW:</p>
                    <img src={paymentPreview} alt="Payment proof preview" className="w-full max-w-md mx-auto rounded" style={{ border: `2px solid ${palette.graphite}` }} />
                  </div>
                )}
                
                {paymentFile && paymentFile.type === 'application/pdf' && (
                  <div className="mt-4 border p-4" style={{ borderColor: palette.graphite, backgroundColor: palette.obsidian }}>
                    <p className="text-xs font-bold uppercase tracking-wider" style={{ color: palette.greige }}>✓ PDF FILE UPLOADED: {paymentFile.name}</p>
                  </div>
                )}
              </div>
            )}

            <button 
              type="submit" disabled={isSubmitting || isCompressing}
              className="w-full py-5 font-black text-sm uppercase tracking-[0.2em] transition-all hover:scale-[1.02] disabled:opacity-50 disabled:hover:scale-100 cursor-pointer"
              style={{ backgroundColor: palette.stucco, color: palette.onyx, boxShadow: `0 0 15px ${palette.greige}40` }}
            >
              {isCompressing ? 'COMPRESSING FILE...' : isSubmitting ? 'PROCESSING...' : (isPaid ? 'SUBMIT REGISTRATION' : 'REGISTER NOW')}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
